class Solution(object):
    def maximumSum(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        def get_square_free_part(n):
            """Get product of primes with odd exponents in factorization of n"""
            result = 1
            d = 2
            while d * d <= n:
                count = 0
                while n % d == 0:
                    count += 1
                    n //= d
                if count % 2 == 1:
                    result *= d
                d += 1
            if n > 1:
                result *= n
            return result

        # Group numbers by their square-free part
        groups = {}
        for i, num in enumerate(nums):
            idx = i + 1  # 1-indexed
            sf = get_square_free_part(idx)
            if sf not in groups:
                groups[sf] = []
            groups[sf].append(num)

        # For each group, sum all values
        max_sum = 0
        for sf in groups:
            group_sum = sum(groups[sf])
            max_sum = max(max_sum, group_sum)

        return max_sum
